&lt;p style=&quot;&quot;&gt;By checking options and substituting accordingly.&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;1)&amp;nbsp;&lt;span style=&quot;&quot;&gt;f o k g o d m o k&amp;nbsp;&amp;rarr; g&amp;nbsp;&lt;strong&gt;f&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d k&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;m -&amp;nbsp;&lt;strong&gt;g&lt;/strong&gt;&amp;nbsp;f&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;d&lt;/strong&gt;&amp;nbsp;k k&amp;nbsp;&lt;strong&gt;m&lt;/strong&gt;&amp;nbsp;- g f o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;k m&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li style=&quot;&quot;&gt;&lt;span style=&quot;&quot;&gt;Here &lt;strong&gt;&amp;quot;gfoodkkm&amp;quot;&lt;/strong&gt; is repeated&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;2)&amp;nbsp;&lt;span style=&quot;&quot;&gt;f o k g o d f o k&amp;nbsp;&amp;rarr; g&amp;nbsp;&lt;strong&gt;f&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d k&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;m -&amp;nbsp;&lt;strong&gt;g&lt;/strong&gt;&amp;nbsp;f&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;d&lt;/strong&gt;&amp;nbsp;k k&amp;nbsp;&lt;strong&gt;f&lt;/strong&gt;&amp;nbsp;- g f o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;k m&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;3)&amp;nbsp;&lt;span style=&quot;&quot;&gt;f o k d o d m o k&amp;nbsp;&amp;rarr; g&amp;nbsp;&lt;strong&gt;f&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d k&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;m -&amp;nbsp;&lt;strong&gt;d&lt;/strong&gt;&amp;nbsp;f&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;d&lt;/strong&gt;&amp;nbsp;k k&amp;nbsp;&lt;strong&gt;m&lt;/strong&gt;&amp;nbsp;- g f o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;k m&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;4)&amp;nbsp;&lt;span style=&quot;&quot;&gt;f o k g o d m o m&amp;nbsp;&amp;rarr; g&amp;nbsp;&lt;strong&gt;f&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d k&amp;nbsp;&lt;strong&gt;k&lt;/strong&gt;&amp;nbsp;m -&amp;nbsp;&lt;strong&gt;g&lt;/strong&gt;&amp;nbsp;f&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;o&amp;nbsp;&lt;strong&gt;d&lt;/strong&gt;&amp;nbsp;k k&amp;nbsp;&lt;strong&gt;m&lt;/strong&gt;&amp;nbsp;- g f o&amp;nbsp;&lt;strong&gt;o&lt;/strong&gt;&amp;nbsp;d&amp;nbsp;&lt;strong&gt;m&lt;/strong&gt;&amp;nbsp;k m&lt;/span&gt;&lt;/p&gt;

