	&lt;li&gt;Option (1) gives the pattern of :-&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;g&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;f&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;o&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;o&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;d k&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;k&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;m -&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;g&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;f&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;o&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;o&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;d&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;k k&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;m&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;- g f o&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;o&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;d&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;k&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;k m&lt;/span&gt;&lt;/li&gt;
